const res = await fetch("https://terminalfeed.io/api/pro/briefing", {
  headers: { Authorization: "Bearer tf_live_<64-char-hex>" },
});
const data = await res.json();
console.log(data);
console.log("credits left:", res.headers.get("X-Credits-Remaining"));

const url = new URL("https://terminalfeed.io/api/pro/macro");
url.searchParams.set("history", "30d");
const res = await fetch(url, {
  headers: { Authorization: "Bearer tf_live_<64-char-hex>" },
});
const macro = await res.json();
console.log("Fed rate:", macro.economic.fed_rate.value);

const url = new URL("https://terminalfeed.io/api/pro/crypto-deep");
url.searchParams.set("coins", "btc,eth,sol");
const res = await fetch(url, { headers: { Authorization: "Bearer tf_live_<64-char-hex>" } });
const d = await res.json();
for (const c of d.coins_top50) console.log(c.symbol, c.price_usd);

const res = await fetch("https://terminalfeed.io/api/payment/buy-credits", {
  method: "POST",
  headers: { "Content-Type": "application/json" },
  body: JSON.stringify({ amount_usd: 1.00 }),
});
const quote = await res.json();
console.log("Send", quote.amount_usd, "USDC to", quote.wallet);

const res = await fetch("https://terminalfeed.io/api/payment/confirm", {
  method: "POST",
  headers: { "Content-Type": "application/json" },
  body: JSON.stringify({ tx_hash: "0xabc...", nonce: "tf-..." }),
});
const { token, credits } = await res.json();

const res = await fetch("https://terminalfeed.io/api/payment/balance", {
  headers: { Authorization: "Bearer tf_live_<64-char-hex>" },
});
const balance = await res.json();
console.log("Credits remaining:", balance.credits);

import OpenAI from "openai";
const tools = (await fetch("https://terminalfeed.io/api/llm-tools?format=openai").then(r => r.json())).openai;
const openai = new OpenAI();
const resp = await openai.chat.completions.create({
  model: "gpt-4o",
  tools,
  messages: [{ role: "user", content: "Get the latest BTC price." }],
});

const res = await fetch("https://terminalfeed.io/api/pro/sentiment", {
  headers: { Authorization: "Bearer tf_live_<64-char-hex>" },
});
const data = await res.json();
for (const t of data.trending.slice(0, 5)) {
  console.log(t.symbol, t.sentiment_label, t.mention_count_24h);
}

const url = new URL("https://terminalfeed.io/api/pro/world-deltas");
url.searchParams.set("since", new Date(Date.now() - 5*60_000).toISOString());
const res = await fetch(url, { headers: { Authorization: "Bearer tf_live_<64-char-hex>" } });
const data = await res.json();
for (const ev of data.events) console.log(ev.type, ev.severity, ev.data);

import OpenAI from "openai";
const TOKEN = "tf_live_<64-char-hex>";
const ctx = await fetch("https://terminalfeed.io/api/pro/agent-context", {
  headers: { Authorization: `Bearer ${TOKEN}` },
}).then(r => r.json());

const openai = new OpenAI();
const resp = await openai.chat.completions.create({
  model: "gpt-4o",
  messages: [
    { role: "system", content: ctx.system_prompt },
    { role: "user", content: "What are the most notable signals in the current world state?" },
  ],
});

const m = await fetch("https://terminalfeed.io/api/pro/correlation-matrix", {
  headers: { Authorization: `Bearer ${TOKEN}` },
}).then(r => r.json());
const btcEth = m.matrix.BTC.ETH;
console.log("BTC-ETH:", btcEth);
